class Solution {
    // Function to find k maximum sum combinations from two arrays
    maxCombinations(nums1, nums2, k) {
        // Sort both arrays descending to prioritize largest values
        nums1.sort((a, b) => b - a);
        nums2.sort((a, b) => b - a);

        // Use an array to simulate max-heap behavior
        const heap = [];
        // Set to track visited index pairs so we avoid duplicates
        const visited = new Set();

        // Push the initial best combination (0,0)
        heap.push([nums1[0] + nums2[0], 0, 0]);
        visited.add(`0,0`);

        // Array to store results
        const result = [];

        // Loop k times to get top k sums
        for (let count = 0; count < k; count++) {
            // Sort heap descending by sum and pop the max each time
            heap.sort((a, b) => b[0] - a[0]);
            const [sum, i, j] = heap.shift();
            result.push(sum);

            // Next candidate (i+1, j)
            if (i + 1 < nums1.length) {
                const key1 = `${i + 1},${j}`;
                if (!visited.has(key1)) {
                    heap.push([nums1[i + 1] + nums2[j], i + 1, j]);
                    visited.add(key1);
                }
            }

            // Next candidate (i, j+1)
            if (j + 1 < nums2.length) {
                const key2 = `${i},${j + 1}`;
                if (!visited.has(key2)) {
                    heap.push([nums1[i] + nums2[j + 1], i, j + 1]);
                    visited.add(key2);
                }
            }
        }

        // Return the final top k sums
        return result;
    }
}

